/**
 * Context builder — assembles project data into a concise text summary
 * that fits within LLM context windows for AI-assisted scheduling.
 */

import { prisma } from '../db.js';

/**
 * Build a text summary of the project for inclusion in AI prompts.
 * Keeps output compact to fit within Ollama context limits (~4K tokens).
 */
export async function buildProjectContext(projectId: string): Promise<string> {
  const [project, tasks, deps, resources, assignments] = await Promise.all([
    prisma.project.findUniqueOrThrow({ where: { id: projectId } }),
    prisma.task.findMany({
      where: { projectId },
      orderBy: { sortOrder: 'asc' },
      take: 200, // cap to prevent token overflow
    }),
    prisma.dependency.findMany({ where: { projectId } }),
    prisma.resource.findMany({ where: { projectId } }),
    prisma.assignment.findMany({ where: { task: { projectId } } }),
  ]);

  const lines: string[] = [];

  // Project header
  lines.push(`Project: ${project.name}`);
  lines.push(`Start: ${project.startDate.toISOString().split('T')[0]}`);
  if (project.finishDate) {
    lines.push(`Finish: ${project.finishDate.toISOString().split('T')[0]}`);
  }
  if (project.statusDate) {
    lines.push(`Status Date: ${project.statusDate.toISOString().split('T')[0]}`);
  }
  lines.push(`Schedule From: ${project.scheduleFrom}`);
  lines.push(`Tasks: ${tasks.length}, Dependencies: ${deps.length}, Resources: ${resources.length}`);
  lines.push('');

  // Task list (compact format)
  lines.push('Tasks (ID | Name | Duration(d) | Start | Finish | %Complete | Critical):');
  for (const t of tasks) {
    const durDays = (t.durationMinutes / 480).toFixed(1);
    const start = t.start.toISOString().split('T')[0];
    const finish = t.finish.toISOString().split('T')[0];
    const crit = t.isCritical ? 'Y' : 'N';
    const indent = '  '.repeat(t.outlineLevel);
    lines.push(
      `${indent}${t.id.slice(0, 8)} | ${t.name} | ${durDays}d | ${start} | ${finish} | ${t.percentComplete}% | ${crit}`,
    );
  }
  lines.push('');

  // Dependencies
  if (deps.length > 0) {
    lines.push('Dependencies (From -> To | Type | Lag):');
    for (const d of deps.slice(0, 100)) {
      const fromTask = tasks.find((t) => t.id === d.fromTaskId);
      const toTask = tasks.find((t) => t.id === d.toTaskId);
      const fromName = fromTask?.name ?? d.fromTaskId.slice(0, 8);
      const toName = toTask?.name ?? d.toTaskId.slice(0, 8);
      const lagDays = d.lagMinutes !== 0 ? ` | ${(d.lagMinutes / 480).toFixed(1)}d lag` : '';
      lines.push(`  ${fromName} -> ${toName} | ${d.type}${lagDays}`);
    }
    lines.push('');
  }

  // Resources
  if (resources.length > 0) {
    lines.push('Resources:');
    for (const r of resources) {
      lines.push(`  ${r.name} (${r.type}, ${(r.maxUnits * 100).toFixed(0)}%)`);
    }
    lines.push('');
  }

  // Assignment summary
  if (assignments.length > 0) {
    lines.push(`Assignments: ${assignments.length} total`);
  }

  return lines.join('\n');
}
